import os
import boto3
import logging
import json

# Configure logging
logger = logging.getLogger()
logger.setLevel(os.environ.get('LOG_LEVEL', 'INFO').upper())

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

def lambda_handler(event, context):
    """
    AWS Lambda function to process user-uploaded images from S3.
    Reads an image from an S3 input bucket, performs a dummy processing step,
    writes a result back to an S3 output bucket, and sends an SNS notification.
    """
    logger.info(f"Received event: {json.dumps(event)}")

    # Configuration from environment variables
    # For MVP, you might hardcode these, but env vars are better practice
    OUTPUT_BUCKET = os.environ.get('OUTPUT_BUCKET', 'your-output-bucket')
    SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', 'arn:aws:sns:your-region:your-account-id:your-sns-topic-name')
    
    # Ensure output bucket and SNS topic are configured
    if not OUTPUT_BUCKET or not SNS_TOPIC_ARN:
        logger.error("OUTPUT_BUCKET or SNS_TOPIC_ARN environment variables are not set.")
        return {
            'statusCode': 500,
            'body': json.dumps('Configuration error: OUTPUT_BUCKET or SNS_TOPIC_ARN not set.')
        }

    records = event.get('Records', [])
    if not records:
        logger.warning("No S3 records found in the event.")
        return {
            'statusCode': 200,
            'body': json.dumps('No S3 records to process.')
        }

    for record in records:
        if 's3' not in record:
            logger.warning(f"Record does not contain S3 data: {json.dumps(record)}")
            continue

        bucket_name = record['s3']['bucket']['name']
        object_key = record['s3']['object']['key']

        logger.info(f"Processing image: s3://{bucket_name}/{object_key}")

        try:
            # 1. Read from S3
            response = s3_client.get_object(Bucket=bucket_name, Key=object_key)
            image_content = response['Body'].read()
            logger.info(f"Successfully read image '{object_key}' from bucket '{bucket_name}'. Size: {len(image_content)} bytes.")

            # Dummy processing step
            # In a real application, you would use Pillow, OpenCV, or other libraries here.
            # For this MVP, let's just simulate some processing.
            processed_data = f"Processed content for {object_key}. Original size: {len(image_content)} bytes."
            processed_file_name = f"processed_{os.path.basename(object_key)}.txt" # Use .txt for dummy data

            # 2. Write results back to S3
            output_key = f"processed/{processed_file_name}"
            s3_client.put_object(Bucket=OUTPUT_BUCKET, Key=output_key, Body=processed_data.encode('utf-8'))
            logger.info(f"Successfully wrote processed data to s3://{OUTPUT_BUCKET}/{output_key}")

            # 3. Send notifications via SNS
            sns_message = {
                "message": f"Image '{object_key}' successfully processed.",
                "input_bucket": bucket_name,
                "input_key": object_key,
                "output_bucket": OUTPUT_BUCKET,
                "output_key": output_key,
                "status": "SUCCESS"
            }
            sns_client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Message=json.dumps(sns_message),
                Subject=f"Image Processing Success: {object_key}"
            )
            logger.info(f"SNS notification sent for '{object_key}'.")

        except Exception as e:
            logger.error(f"Error processing image '{object_key}': {e}", exc_info=True)
            # Send failure notification via SNS
            error_message = {
                "message": f"Error processing image '{object_key}': {str(e)}",
                "input_bucket": bucket_name,
                "input_key": object_key,
                "status": "FAILED",
                "error_details": str(e)
            }
            try:
                sns_client.publish(
                    TopicArn=SNS_TOPIC_ARN,
                    Message=json.dumps(error_message),
                    Subject=f"Image Processing Failed: {object_key}"
                )
                logger.info(f"SNS error notification sent for '{object_key}'.")
            except Exception as sns_e:
                logger.error(f"Failed to send SNS error notification for '{object_key}': {sns_e}", exc_info=True)

    return {
        'statusCode': 200,
        'body': json.dumps('Image processing attempt completed.')
    }